('computer-science:2-2-3e-subprograms-and-random-numbers:match:e847cf85', 'computer-science', 'computer-science:2-2-3e-subprograms-and-random-numbers', '2.2.3e Sub Programs and Random Numbers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Global variable”?", "options": ["Can be accessed from anywhere in the program, including inside sub programs", "The actual value supplied for a parameter when a sub program is called", "A sub program that carries out a task but does not return a value", "Writing code once and calling it many times, instead of repeating it"]}'::jsonb, '{"answer": 0, "explain": "“Global variable” means: Can be accessed from anywhere in the program, including inside sub programs"}'::jsonb),
('computer-science:2-2-3e-subprograms-and-random-numbers:match:28b28dcf', 'computer-science', 'computer-science:2-2-3e-subprograms-and-random-numbers', '2.2.3e Sub Programs and Random Numbers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Scope”?", "options": ["Breaking a large problem down into smaller, named sub programs", "Returns a random integer between a and b, inclusive of both", "The part of a program where a variable can be accessed", "Exists only while the sub program it is declared inside is running"]}'::jsonb, '{"answer": 2, "explain": "“Scope” means: The part of a program where a variable can be accessed"}'::jsonb),
