('computer-science:2-2-3e-subprograms-and-random-numbers:match:4de4579d', 'computer-science', 'computer-science:2-2-3e-subprograms-and-random-numbers', '2.2.3e Sub Programs and Random Numbers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “random(a, b)”?", "options": ["A sub program that returns a value using return", "Exists only while the sub program it is declared inside is running", "Returns a random integer between a and b, inclusive of both", "The keywords that mark the end of a function / procedure definition"]}'::jsonb, '{"answer": 2, "explain": "“random(a, b)” means: Returns a random integer between a and b, inclusive of both"}'::jsonb),
('computer-science:2-2-3e-subprograms-and-random-numbers:match:ec8de80f', 'computer-science', 'computer-science:2-2-3e-subprograms-and-random-numbers', '2.2.3e Sub Programs and Random Numbers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “endfunction / endprocedure”?", "options": ["The keywords that mark the end of a function / procedure definition", "The value a function sends back to wherever it was called from", "The part of a program where a variable can be accessed", "The actual value supplied for a parameter when a sub program is called"]}'::jsonb, '{"answer": 0, "explain": "“endfunction / endprocedure” means: The keywords that mark the end of a function / procedure definition"}'::jsonb),
('computer-science:2-3-1-defensive-design:exam:5d5a6252', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify the validation check that confirms a value lies between a stated minimum and a stated maximum.</p>", "options": ["Format check, since this confirms that data follows a required pattern such as a specific arrangement of letters and digits", "Range check", "Presence check, since this simply confirms that something has actually been entered into the field", "Length check, since this confirms that the correct number of characters have been typed by the user"], "hint": "Which check uses a minimum and a maximum value?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Range check</strong></li></ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Only the correct option scores; 2 or more ticks scores 0.</li></ul>\n</div>", "modelAnswer": "Range check."}'::jsonb),
('computer-science:2-3-1-defensive-design:exam:2f1dc680', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'exam', 'mcq', 1, '{"num": "Q2", "question": "<p>Tick <strong>one</strong> box to identify the technique that confirms a user is who they claim to be before letting them use a system.</p>", "options": ["Verification, since this simply confirms that data was typed or copied correctly by the user", "Authentication", "Validation, since this confirms that data entered is sensible before the program goes on to use it", "Maintainability, since this is about writing code that other programmers can read and change easily"], "hint": "Think of logging in with a username and password."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Authentication</strong></li></ul>\n</div>", "modelAnswer": "Authentication."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:9e286ebe', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "What is defensive design mainly concerned with?", "options": ["Making a program''s file size as small as possible so that it downloads and installs more quickly", "Anticipating misuse and designing a program so it copes with unexpected, wrong or malicious input", "Translating source code into machine code so that the processor is able to run the program without any errors", "Choosing which programming language a program should be written in before development begins"]}'::jsonb, '{"answer": 1, "explain": "Defensive design is about anticipating problems with input and coping with them, not about file size, translation or language choice."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:1f5424ec', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "A form asks for a whole number between 1 and 5 (a star rating). Which check would reject the value 8?", "options": ["A presence check, because the box was actually filled in and something was definitely typed into it", "A range check", "A format check, because 8 is a single digit and does not follow any particular pattern of characters", "A length check, because the number 8 is exactly one character long when it is typed into the box"]}'::jsonb, '{"answer": 1, "explain": "8 is a valid whole number that was entered and is one character long — it fails only because it''s outside 1-5, which is what a range check tests."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:d4ef4493', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "Which check would catch someone typing ''twelve'' into a box that expects a whole number?", "options": ["A range check, because the word ''twelve'' is clearly not a value that lies between any sensible minimum and maximum", "A type check", "A presence check, because the box was left with something inside it rather than being submitted completely empty", "A format check, because the word twelve does not contain the letters and digits used in a typical postcode"]}'::jsonb, '{"answer": 1, "explain": "''twelve'' is text, not the whole-number data type expected — this is exactly what a type check is designed to catch."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:5b3c5cba', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "A required ''Email address'' box is submitted with nothing typed into it. Which check catches this?", "options": ["A range check, since an empty box can be thought of as lying below the lowest value that the check allows", "A presence check", "A type check, because an empty box does not contain any data of a recognisable type such as a number", "A length check, because an empty box technically does contain zero characters, which is a valid length"]}'::jsonb, '{"answer": 1, "explain": "Testing whether a box was left blank is exactly what a presence check does."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:47eac326', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "A PIN must be exactly 4 digits. Which check tests the number of characters entered?", "options": ["A format check, because a PIN made only of digits does still follow a recognisable pattern of characters", "A length check", "A range check, because each individual digit in the PIN could be checked to see that it lies between 0 and 9", "An authentication check, because a PIN is often used together with a username to log a user into a system"]}'::jsonb, '{"answer": 1, "explain": "Counting how many characters were entered and comparing that to a required number is a length check."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:b9f07399', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of a format check?", "options": ["Checking that a percentage mark entered is no less than 0 and no more than 100 before it is stored", "Checking that a National Insurance number matches its usual pattern of letters and digits", "Checking that a ''first name'' box has not been submitted while still completely empty", "Checking that a password entered contains no fewer than eight individual characters in total"]}'::jsonb, '{"answer": 1, "explain": "A format check tests whether data matches a required pattern or layout, like a National Insurance number''s usual arrangement of letters and digits."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:7f301e8b', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "What is the difference between validation and verification?", "options": ["There is no real difference; both terms simply describe exactly the same single process of checking data", "Validation checks data is sensible and follows set rules; verification checks it was entered or copied correctly", "Validation is carried out by a person, whereas verification is always carried out automatically by the program itself", "Validation only applies to numbers, whereas verification only ever applies to text typed in by a user"]}'::jsonb, '{"answer": 1, "explain": "Validation checks the data is sensible/follows rules; verification checks it was entered/copied correctly (e.g. matches the original)."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:b3ffe9db', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "Which of these is a method of verification?", "options": ["Rejecting an age entered as -5, because a negative age falls outside of any sensible range of values", "Asking a user to type their password twice and checking that the two entries match", "Rejecting a mark of 150 out of 100, because it is clearly higher than the maximum mark that is possible", "Rejecting a username box that has been submitted by a user while it was still completely empty"]}'::jsonb, '{"answer": 1, "explain": "Double-entry (typing a value twice and comparing) is a verification method, checking data was entered correctly. The others are range and presence checks."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:cf6c0c14', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "What is authentication?", "options": ["Automatically checking that data entered into a program follows a set of sensible, pre-defined rules", "Confirming a user''s identity, most commonly with a username and password, before granting access", "Splitting a long program into smaller, named sub-programs that each carry out one clear task", "Adding comments to a program''s code so that another programmer can understand what it does"]}'::jsonb, '{"answer": 1, "explain": "Authentication confirms WHO a user is before granting access — most commonly a username and password."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:2cd483d2', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "Which of these would make two-step verification harder for an attacker to bypass than a password alone?", "options": ["Making the password shorter, since a shorter password is naturally faster for the real user to type in", "Requiring a one-time code, such as one sent by text message, in addition to the password", "Removing the username requirement, so that only a password needs to be entered to gain access", "Allowing an unlimited number of password attempts, so the real user is never accidentally locked out"]}'::jsonb, '{"answer": 1, "explain": "Two-step verification adds a second, separate factor (like a one-time code) — a stolen password alone is then not enough to get in."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:ff610321', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "How does splitting a program into sub-programs improve its maintainability?", "options": ["It always makes the finished program run faster, since sub-programs are processed before any other code", "Each sub-program can be read, tested and reused separately, making the whole program easier to work with", "It removes the need to test the program at all, since each sub-program is assumed to already be correct", "It means variable names no longer need to be meaningful, since sub-programs replace the need for good naming"]}'::jsonb, '{"answer": 1, "explain": "Sub-programs let each task be read, tested and reused on its own — that''s what improves maintainability, not speed or naming."}'::jsonb),
('computer-science:2-3-1-defensive-design:mcq:fb9df1ac', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'mcq', 'mcq', 1, '{"question": "Which of these improves a program''s maintainability?", "options": ["Writing the entire program as a single very long block of code with no separate named sections at all", "Using consistent indentation to show the structure of loops, selection statements and sub-programs", "Giving every variable in the program the shortest possible name, such as a, b and c, wherever possible", "Removing all comments from the finished code once the program has been fully tested and is working"]}'::jsonb, '{"answer": 1, "explain": "Consistent indentation shows the code''s structure at a glance, making it easier for another programmer to follow — that''s maintainability."}'::jsonb),
('computer-science:2-3-1-defensive-design:tf:ac0a64d4', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tf', 'tf', 1, '{"question": "Input validation checks that data is sensible and follows set rules before the program uses it."}'::jsonb, '{"answer": true, "explain": "Correct — that is exactly what input validation does."}'::jsonb),
('computer-science:2-3-1-defensive-design:tf:193e26d4', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tf', 'tf', 1, '{"question": "A range check confirms that data has been typed with the correct number of characters."}'::jsonb, '{"answer": false, "explain": "That describes a length check. A range check confirms a value lies between a stated minimum and maximum."}'::jsonb),
('computer-science:2-3-1-defensive-design:tf:a3fee5b0', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tf', 'tf', 1, '{"question": "Verification checks that data has been entered or copied correctly, for example by asking a user to type it twice."}'::jsonb, '{"answer": true, "explain": "Correct — that is verification (double-entry checks whether the two entries match)."}'::jsonb),
('computer-science:2-3-1-defensive-design:tf:a81dd787', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tf', 'tf', 1, '{"question": "Authentication is the process of checking that a numeric value lies between a minimum and maximum."}'::jsonb, '{"answer": false, "explain": "That describes a range check. Authentication confirms a user''s identity, most commonly with a username and password."}'::jsonb),
('computer-science:2-3-1-defensive-design:tf:744e0b4f', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tf', 'tf', 1, '{"question": "Breaking a program into sub-programs can make it easier to test and reuse individual parts of the code."}'::jsonb, '{"answer": true, "explain": "Correct — each sub-program can be read, tested and reused on its own."}'::jsonb),
('computer-science:2-3-1-defensive-design:tf:1da963f1', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tf', 'tf', 1, '{"question": "Using variable names such as x and y instead of studentAge makes a program more maintainable."}'::jsonb, '{"answer": false, "explain": "The opposite is true — meaningful names like studentAge make code easier to understand than short, unclear ones like x and y."}'::jsonb),
('computer-science:2-3-1-defensive-design:tf:e6130279', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tf', 'tf', 1, '{"question": "A validation check can guarantee that the data entered is actually true."}'::jsonb, '{"answer": false, "explain": "Validation only checks that data is sensible and follows set rules (e.g. in range) — it cannot know whether the value entered is truthful."}'::jsonb),
('computer-science:2-3-1-defensive-design:tf:b2d1fd0d', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tf', 'tf', 1, '{"question": "Comments and consistent indentation both help make a program''s code more maintainable."}'::jsonb, '{"answer": true, "explain": "Correct — both make the code easier for another programmer to read and follow."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:3e89fdd9', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "What is defensive design?", "reading": "<h4>Designing a program so it copes, rather than crashes</h4>\n<ul>\n<li><strong>Defensive design</strong> means writing a program so that it keeps behaving sensibly even when something unexpected happens — a user types the wrong kind of data, leaves a box empty, or even tries to misuse the program on purpose.</li>\n<li>A program that has <strong>not</strong> been designed defensively might <strong>crash</strong>, produce a <strong>meaningless result</strong>, or let someone access data or features they shouldn''t.</li>\n<li>This page covers three defensive techniques: <strong>input validation</strong> (checking data before the program uses it), <strong>authentication</strong> (checking who the user is) and <strong>maintainability</strong> (writing code that other programmers can understand and safely change).</li>\n</ul>", "question": "What is the main aim of defensive design?", "options": ["To make a program''s source code as short as possible, since a shorter program is assumed to always run more quickly", "To write a program that keeps behaving sensibly even when a user enters unexpected, wrong or malicious data", "To translate a finished program from a high-level language into machine code so the processor can run it", "To make sure a program only ever needs to be tested once, before it is finally released to its actual users"]}'::jsonb, '{"answer": 1, "explain": "Defensive design is about anticipating things going wrong — unexpected, wrong or malicious input — and coping with it, rather than crashing or misbehaving."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:3d3fe070', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Anticipating misuse", "reading": "<h4>Thinking ahead about what could go wrong</h4>\n<ul>\n<li><strong>Anticipating misuse</strong> means thinking, before the program is even finished, about all the ways a user might enter data that is <strong>unexpected</strong>, <strong>wrong</strong> or even <strong>malicious</strong> — and designing the program so it doesn''t crash or behave badly when this happens.</li>\n<li>Examples a programmer should plan for: typing letters into a box that expects a number; leaving a required box empty; entering a number that is far too big or too small to make sense; or deliberately entering unusual data to try to break the program.</li>\n<li>A well-designed program <strong>expects</strong> these situations and responds calmly — for example by rejecting the input and asking again — instead of crashing or producing nonsense output.</li>\n</ul>", "question": "Which of these best describes ''anticipating misuse'' in defensive design?", "options": ["Fixing a program''s bugs only after real users have already found them by using the finished program", "Thinking in advance about the unexpected, wrong or malicious data a user might enter, and designing the program to cope with it", "Writing a program so that it never needs to accept any input from a user at any point while it is running", "Testing a program exactly once, using only data that is already known to be completely correct and expected, before it is ever shown to a real user"]}'::jsonb, '{"answer": 1, "explain": "Anticipating misuse means planning for unexpected, wrong or malicious input BEFORE it happens, so the program can cope with it rather than crash."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:e8952e86', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Input validation: checking before it''s used", "reading": "<h4>Catching bad data before the program uses it</h4>\n<ul>\n<li><strong>Input validation</strong> is an automatic check, built into the program, that tests whether data entered is <strong>sensible</strong> and follows a set of rules — <strong>before</strong> the program goes on to use that data.</li>\n<li>If the data fails the check, the program should <strong>reject it</strong> and ask the user to try again, rather than carrying on and risking a crash or a wrong result.</li>\n<li>There are several standard types of check, each suited to a different kind of problem: <strong>range</strong>, <strong>type</strong>, <strong>presence</strong>, <strong>length</strong> and <strong>format</strong> checks. Each is covered in its own card next.</li>\n</ul>", "question": "When should an input validation check be carried out?", "options": ["After the program has already used the data to calculate and display a result to the user on the screen", "Before the program uses the data, so that unsuitable data can be rejected first", "Only once, the very first time the program is ever run on a brand new computer", "Only if the program''s user specifically asks for their data to be checked before it is used"]}'::jsonb, '{"answer": 1, "explain": "Validation happens BEFORE the data is used, so unsuitable data can be caught and rejected before it causes a problem."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:4671d09d', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Range check", "reading": "<h4>Is the value between a minimum and a maximum?</h4>\n<ul>\n<li>A <strong>range check</strong> tests whether a numeric value entered lies between a stated <strong>minimum</strong> and <strong>maximum</strong>.</li>\n<li>Example: a percentage mark should be no less than 0 and no more than 100.</li>\n</ul>\n<div class=\"code-block\">if mark &lt; 0 OR mark &gt; 100 then\n  print(\"Invalid mark\")\nendif</div>\n<ul>\n<li>Range checks are used wherever a sensible value has natural upper and/or lower limits — a day of the month (1–31), an age (0–120), a quantity ordered (1 or more), and so on.</li>\n</ul>", "question": "Which of these is an example of a range check?", "options": ["Checking that a username box has not been left completely empty by the user before it is submitted", "Checking that an entered day-of-the-month is no less than 1 and no more than 31", "Checking that an entered postcode matches the pattern of letters and digits used by real postcodes", "Checking that a password entered by the user is at least eight characters long before it is accepted"]}'::jsonb, '{"answer": 1, "explain": "A range check tests a value against a minimum and maximum — here, that a day is between 1 and 31. The others are presence, format and length checks."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:dcef53e4', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Type check", "reading": "<h4>Is the value the correct kind of data?</h4>\n<ul>\n<li>A <strong>type check</strong> tests whether the data entered is of the <strong>correct data type</strong> — for example, that a value that should be a whole number is actually a whole number, and not text.</li>\n<li>Example: if a program asks for someone''s age, entering \"twelve\" instead of 12 should be rejected by a type check.</li>\n</ul>\n<div class=\"code-block\">age = input(\"Enter your age: \")\n// a type check confirms ''age'' can be treated as a whole number\n// before it is used in any further calculation</div>\n<ul>\n<li>Type checks stop a program <strong>crashing</strong> when it tries to do maths with something that isn''t actually a number.</li>\n</ul>", "question": "What does a type check test?", "options": ["That the data entered lies between a stated minimum value and a stated maximum value", "That the data entered is of the correct data type, for example a whole number rather than text", "That the data entered has not been left blank by the user before the form is submitted", "That the data entered matches a required pattern, such as the exact layout of an email address"]}'::jsonb, '{"answer": 1, "explain": "A type check confirms the data is of the expected kind (e.g. a number, not text). Range, presence and format checks test other things."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:94517e72', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Presence check", "reading": "<h4>Has something actually been entered?</h4>\n<ul>\n<li>A <strong>presence check</strong> tests whether a field has been <strong>left empty</strong>. If nothing has been entered, the data fails the check.</li>\n<li>Example: a compulsory \"Name\" box on a registration form should not be allowed to stay blank.</li>\n</ul>\n<div class=\"code-block\">name = input(\"Enter your name: \")\nif name == \"\" then\n  print(\"Name cannot be blank\")\nendif</div>\n<ul>\n<li>Presence checks are usually the <strong>simplest</strong> check to apply, and are often combined with other checks on the same field.</li>\n</ul>", "question": "A presence check on a ''Name'' field would reject which of these?", "options": ["The name ''Ali'', because it is shorter than most other names that are typically entered into this kind of field", "An empty box, where the user submitted the form without typing anything into the Name field at all", "The name ''Priya'', since it contains no numbers or unusual symbols that would normally cause a program to fail", "The name ''Jordan'', because it happens to also be the name of a country as well as being a common first name"]}'::jsonb, '{"answer": 1, "explain": "A presence check only tests whether something was entered at all — it rejects an empty field, regardless of what a valid name might look like."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:4b5c4f58', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Length check", "reading": "<h4>Is it the right number of characters?</h4>\n<ul>\n<li>A <strong>length check</strong> tests whether the number of characters entered falls within an allowed range.</li>\n<li>Example: a password might be required to be between 8 and 16 characters long.</li>\n</ul>\n<div class=\"code-block\">password = input(\"Enter a password (8-16 characters): \")\nif len(password) &lt; 8 OR len(password) &gt; 16 then\n  print(\"Invalid length\")\nendif</div>\n<ul>\n<li>Length checks are common for passwords, PIN codes and reference numbers, where a valid value always has a fixed or bounded number of characters.</li>\n</ul>", "question": "A system requires passwords to be between 8 and 16 characters long. Which check tests this rule?", "options": ["A range check, because 8 and 16 look like they could be the minimum and maximum values of an ordinary number", "A length check", "A presence check, because a password box must never be left empty by the user under any circumstance", "A type check, because a password is always stored by the computer as a sequence of individual text characters"]}'::jsonb, '{"answer": 1, "explain": "Counting characters and comparing to an allowed minimum/maximum number of characters is a length check, not a range check (which tests a numeric value''s size)."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:b9f07399', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Format check", "reading": "<h4>Does it match the expected pattern?</h4>\n<ul>\n<li>A <strong>format check</strong> tests whether data matches a required <strong>pattern</strong> or layout.</li>\n<li>Example: a UK postcode follows a recognisable pattern of letters and digits; an email address must contain an \"@\" symbol with text on both sides.</li>\n</ul>\n<div class=\"code-block\">// simplified idea: does the email contain an @ symbol?\nemail = input(\"Enter your email: \")\nif NOT (email contains \"@\") then\n  print(\"Invalid format\")\nendif</div>\n<ul>\n<li>Format checks are used whenever valid data has to look a particular way, even though its exact value can vary.</li>\n</ul>", "question": "Which of these is an example of a format check?", "options": ["Checking that an entered exam mark is no less than 0 and no more than 100 before it is accepted by the program", "Checking that an entered email address contains an ''@'' symbol with text on both sides of it", "Checking that a ''Surname'' field has not been submitted completely empty by the person filling in the form", "Checking that an entered PIN code is exactly four characters long before the program will accept it as valid"]}'::jsonb, '{"answer": 1, "explain": "A format check tests whether data follows a required pattern or layout — like an email address needing an ''@'' symbol. The others are range, presence and length checks."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:1e8148ad', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Validation loops: keep asking until it''s valid", "reading": "<h4>Re-asking until a valid value is entered</h4>\n<ul>\n<li>In practice, validation is usually combined with a <strong>loop</strong>: the program keeps <strong>re-asking</strong> for input until the value entered actually passes the check.</li>\n<li>A <code>do … until</code> loop is a natural fit, because it always runs its body <strong>at least once</strong> (you need to ask at least once before there''s anything to check).</li>\n</ul>\n<div class=\"code-block\">do\n  age = input(\"Enter your age (0-120): \")\nuntil age &gt;= 0 AND age &lt;= 120\nprint(\"Thank you\")</div>\n<ul>\n<li>A <code>while</code> loop works too, as long as it tests the <strong>opposite</strong> (invalid) condition and asks for the very first input before the loop starts:</li>\n</ul>\n<div class=\"code-block\">age = input(\"Enter your age (0-120): \")\nwhile age &lt; 0 OR age &gt; 120\n  age = input(\"Invalid. Enter your age (0-120): \")\nendwhile</div>", "question": "Why does a do…until loop suit a validation re-ask pattern well?", "options": ["Because a do…until loop is the only kind of loop that is able to contain an if statement anywhere inside it", "It always runs its body at least once, matching the need to ask for input before there''s anything to check", "Because a do…until loop automatically counts exactly how many attempts the user has made before it will finally stop", "Because a do…until loop can only ever be used with numeric data, never with text entered by a user into a box"]}'::jsonb, '{"answer": 1, "explain": "A do…until loop checks its condition AFTER the body, so it always runs at least once — matching the need to ask for input before checking it."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:058c1dc9', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Validation vs verification", "reading": "<h4>Two different questions about data</h4>\n<ul>\n<li><strong>Validation</strong> asks: \"Is this data <strong>sensible</strong>, and does it follow the rules I''ve set?\" It is done automatically by the program (e.g. a range check).</li>\n<li><strong>Verification</strong> asks: \"Was this data entered or copied <strong>correctly</strong>?\" It checks for mistakes in typing or copying, not whether the value itself is sensible.</li>\n<li>Common verification methods: <strong>double-entry</strong> (typing a password twice and comparing the two entries) and <strong>proofreading</strong> (a human checking data against its original source).</li>\n</ul>\n<div class=\"code-block\">password1 = input(\"Enter a password: \")\npassword2 = input(\"Re-enter the password: \")\nif password1 != password2 then\n  print(\"Passwords do not match\")\nendif</div>\n<ul>\n<li><strong>Key point:</strong> a value can pass validation (it''s a sensible-looking value) and still be <strong>wrong</strong> — validation can''t tell if a truthful value was typed. Verification is aimed at catching that kind of mistake.</li>\n</ul>", "question": "A user is asked to type their password twice, and the program checks the two entries match. What is this an example of?", "options": ["A range check, because the program is comparing two values to see whether one lies inside the other", "Verification", "A format check, because the program is confirming that the password follows a required layout or pattern", "Authentication, because entering a password is always specifically an example of authenticating a user"]}'::jsonb, '{"answer": 1, "explain": "Comparing two entries to confirm data was typed correctly is verification (double-entry), not one of the validation checks."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:cf6c0c14', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Authentication", "reading": "<h4>Confirming who the user is</h4>\n<ul>\n<li><strong>Authentication</strong> is the process of confirming a user''s <strong>identity</strong> before allowing them access to a system or its data.</li>\n<li>The most common method is a <strong>username and password</strong>. Good password rules — a minimum length, and a mix of letters, numbers and symbols — make a password harder to guess.</li>\n<li>Some systems add <strong>two-step verification</strong>: after the password, a one-time code (e.g. sent by text message) must also be entered. This means a stolen password alone isn''t enough to get in.</li>\n</ul>\n<div class=\"code-block\">username = input(\"Username: \")\npassword = input(\"Password: \")\nif username == storedUsername AND password == storedPassword then\n  print(\"Access granted\")\nelse\n  print(\"Access denied\")\nendif</div>", "question": "What is authentication?", "options": ["Automatically checking that data entered into a form follows a set of sensible rules before it is used", "Confirming a user''s identity before allowing them access to a system", "Writing program code in a way that makes it easy for another programmer to read and change later", "Checking that data has been typed or copied correctly, for example by entering it a second time"]}'::jsonb, '{"answer": 1, "explain": "Authentication confirms WHO the user is, most commonly with a username and password. The other options describe validation, maintainability and verification."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:35d0fc46', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Maintainability — sub-programs", "reading": "<h4>Breaking a program into smaller pieces</h4>\n<ul>\n<li><strong>Maintainability</strong> means writing a program so that it is easy for a programmer — including one who didn''t originally write it — to read, understand and safely change later.</li>\n<li>One key technique is using <strong>sub-programs</strong> (procedures and functions): splitting a program into smaller, named blocks that each do <strong>one clear job</strong>, instead of writing everything as one long block of code.</li>\n<li>Why it helps: each sub-program can be read, tested and fixed <strong>on its own</strong>; the same sub-program can be <strong>reused</strong> wherever that task is needed, instead of copying the code out again; and the overall structure of the program becomes clearer.</li>\n</ul>", "question": "How does breaking a program into sub-programs improve its maintainability?", "options": ["It makes the finished program noticeably smaller in file size once it has been saved onto a storage device", "It splits the program into smaller, named blocks that can each be read, tested and reused on their own", "It automatically removes the need for the programmer to ever add any comments anywhere in their code", "It guarantees that the program will run faster, since sub-programs are always processed before any other code"]}'::jsonb, '{"answer": 1, "explain": "Sub-programs split code into smaller, reusable, individually-testable blocks — that''s what makes the program easier to maintain."}'::jsonb),
('computer-science:2-3-1-defensive-design:learn:e35e9ec7', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'learn', 'mcq', 1, '{"readingTitle": "Maintainability — naming, indentation and comments", "reading": "<h4>Making the code itself easy to follow</h4>\n<ul>\n<li><strong>Meaningful/descriptive naming</strong> — calling a variable <code>studentAge</code> instead of <code>x</code> tells the next reader what it is for, without them having to trace the whole program to find out.</li>\n<li><strong>Consistent indentation</strong> — lining up code inside loops, selection statements and sub-programs shows the <strong>structure</strong> of the program at a glance, making it far easier to see which lines belong together.</li>\n<li><strong>Comments</strong> — short notes (ignored by the computer when the program runs) that explain <strong>what</strong> a tricky section does or <strong>why</strong> it''s written that way, saving a future reader from having to work it out from scratch.</li>\n</ul>\n<div class=\"code-block\">// Calculate the average of three test scores\naverage = (score1 + score2 + score3) / 3\nprint(average)</div>", "question": "Why do programmers use meaningful variable names, such as studentAge instead of x?", "options": ["Because a program will only run correctly if every single variable name used is at least four letters long", "A meaningful name tells another programmer what the variable is for, making the code easier to understand", "Because meaningful names are the only kind of name that a compiler or interpreter will ever actually accept", "Because using meaningful names is the only way to make sure a program never produces any errors while running"]}'::jsonb, '{"answer": 1, "explain": "Meaningful names make code easier for other programmers (or the same one, later) to read and understand — that''s what maintainability is about."}'::jsonb),
('computer-science:2-3-1-defensive-design:misc:65fd1c89', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a validation check proves the data entered is TRUE, not just sensible-looking.</p><p><strong>✅ The correct idea:</strong> A validation check (like a range check) only tests whether data <strong>follows the rules</strong> that have been set — for example, that an age is between 0 and 120. It has <strong>no way of knowing</strong> whether the value is actually the truth. Someone could type a wrong-but-plausible age, and it would still pass.</p>", "question": "A range check accepts an age of 40 that a user typed in by mistake — their real age is 25. What does this show?", "options": ["That the range check itself must contain a mistake, since it should have been able to detect the wrong value", "That validation checks whether data is sensible and follows the rules set — it cannot know if data is truthful", "That the age of 40 must actually be correct, since a range check would otherwise have rejected the value", "That a type check should have been used here instead of a range check to catch this particular kind of mistake"]}'::jsonb, '{"answer": 1, "explain": "Validation can only test whether data is sensible/in range — it has no way to know whether an entered value is actually true."}'::jsonb),
('computer-science:2-3-1-defensive-design:misc:92b6bd82', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Confusing validation and verification (treating them as the same thing).</p><p><strong>✅ The correct idea:</strong> <strong>Validation</strong> asks whether data is <strong>sensible</strong> and follows set rules (e.g. a range check). <strong>Verification</strong> asks whether data was <strong>entered or copied correctly</strong> — for example, typing a password twice and checking the two entries match. A value can pass one and still fail the other.</p>", "question": "A user types their password twice, and the program checks that both entries match exactly. What is this?", "options": ["A range check, because the program is comparing the sizes of the two password entries against each other", "Verification", "A format check, because the program is confirming that the password matches a required layout of characters", "A type check, because the program is confirming that both entries are made up of the same data type"]}'::jsonb, '{"answer": 1, "explain": "Comparing two entries to see if data was typed correctly is verification, not one of the validation checks."}'::jsonb),
('computer-science:2-3-1-defensive-design:misc:f2e234e0', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking authentication and validation are the same thing.</p><p><strong>✅ The correct idea:</strong> <strong>Authentication</strong> confirms <strong>who the user is</strong> — most commonly a username and password. <strong>Validation</strong> checks that <strong>data entered is sensible</strong>, such as a mark being in range. Logging in is authentication; checking a mark is 0-100 is validation.</p>", "question": "A website asks a returning customer to enter their username and password before showing their order history. What is this an example of?", "options": ["A length check, because both the username and the password are made up of a particular number of characters", "Authentication", "A range check, because a username and password are both compared against a stored minimum and maximum", "A presence check, because the username and password boxes must not be left completely empty by the customer"]}'::jsonb, '{"answer": 1, "explain": "Confirming identity with a username and password before granting access is authentication, not one of the input validation checks."}'::jsonb),
('computer-science:2-3-1-defensive-design:misc:7fe13d6e', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Assuming every check that rejects bad data must be a ''range check'' — treating all checks as one thing.</p><p><strong>✅ The correct idea:</strong> There are <strong>several distinct check types</strong>, each suited to a different problem: <strong>range</strong> (min/max), <strong>type</strong> (correct kind of data), <strong>presence</strong> (something was entered), <strong>length</strong> (number of characters) and <strong>format</strong> (matches a pattern). Match the check to what''s actually wrong with the data.</p>", "question": "A ''Surname'' box is submitted while still completely empty. Which check is designed to catch this?", "options": ["A range check, because an empty box can be thought of as a value that is lower than any allowed minimum", "A presence check", "A format check, because an empty box does not match the usual pattern expected for a surname", "A type check, because an empty box does not contain any data of a specific, recognisable data type"]}'::jsonb, '{"answer": 1, "explain": "An empty box is caught by a presence check specifically — the other checks test different things entirely (range, pattern, data type)."}'::jsonb),
('computer-science:2-3-1-defensive-design:misc:0b10c0a4', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking short, unclear variable names (like a, b, x) save time and don''t really matter.</p><p><strong>✅ The correct idea:</strong> Short names might be quicker to type, but they make code <strong>much harder for another programmer</strong> (or the same one, months later) to understand and safely change. <strong>Meaningful names</strong> — like <code>studentAge</code> instead of <code>x</code> — cost almost nothing extra to write but save real time when the code has to be maintained.</p>", "question": "Why might using the variable name x instead of studentAge cause a problem later on?", "options": ["Because a program containing the name x will always run more slowly than one using the name studentAge", "It makes the code harder for another programmer to understand and safely change later", "Because the name x is not allowed by most programming languages when naming a variable that holds an age", "Because a program is not able to store more than a single variable if any of its names are only one letter long"]}'::jsonb, '{"answer": 1, "explain": "Unclear names like x don''t stop a program running, but they make the code much harder for anyone (including the original author, later) to read and maintain."}'::jsonb),
('computer-science:2-3-1-defensive-design:misc:e3098fd9', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking defensive design is only about stopping a program from crashing.</p><p><strong>✅ The correct idea:</strong> Crash-prevention is only <strong>part</strong> of it. Defensive design also covers <strong>coping gracefully</strong> with wrong or malicious input (not just avoiding a crash), <strong>authentication</strong> (controlling who can access the system) and <strong>maintainability</strong> (so the program can be safely fixed and improved over time).</p>", "question": "Besides stopping a program from crashing, what else does defensive design cover?", "options": ["Nothing else — defensive design is entirely and only about preventing a program from crashing while it runs", "Controlling who can access a system (authentication) and writing code that is easy to maintain and update", "Making sure a program''s user interface uses bright colours so that it is easier for users to look at", "Reducing the total number of lines of code in a program so that it takes up less storage space overall"]}'::jsonb, '{"answer": 1, "explain": "Defensive design is broader than crash-prevention — it also covers controlling access (authentication) and writing maintainable code."}'::jsonb),
('computer-science:2-3-1-defensive-design:tips:33daa0ba', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tips', 'mcq', 1, '{"readingTitle": "tip — Naming and describing a validation check", "reading": "<p>A very common question gives you a scenario and asks you to <strong>name</strong> a suitable validation check, then <strong>describe</strong> how it works for that specific scenario — not just give a generic definition.</p>\n<ul>\n<li>Step 1 — <strong>name</strong> the check: range / type / presence / length / format.</li>\n<li>Step 2 — <strong>describe</strong> it using the actual numbers or example from the question, not a vague general statement.</li>\n</ul>\n<p><strong>Example:</strong> \"A day-of-the-month field must be between 1 and 31.\" Weak answer: \"It checks the number is in range.\" Strong answer: \"A <strong>range check</strong>, which would reject any value entered that is <strong>less than 1 or greater than 31</strong>.\"</p>", "question": "A mark scheme asks you to ''name and describe'' a validation check for a percentage field (0-100). What makes the strongest answer?", "options": ["Simply writing the single word ''validation'' without naming a specific check or describing how it works at all", "Naming the specific check (range check) and describing it using the actual 0-100 limits given in the question", "Describing every possible validation check type in turn, in case the examiner is looking for a different one", "Naming the check but describing what a completely different check, such as a presence check, would do instead"]}'::jsonb, '{"answer": 1, "explain": "Full marks need the specific check named AND described using the scenario''s own numbers/example — not a vague general answer."}'::jsonb),
('computer-science:2-3-1-defensive-design:tips:4cebb9a8', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tips', 'mcq', 1, '{"readingTitle": "explain — Writing a validation loop", "reading": "<p>When you''re asked to write an algorithm that validates input, examiners want to see the input, the loop, and the correct condition — not just the check on its own.</p>\n<ul>\n<li>Use a <code>do … until</code> loop testing the <strong>valid</strong> condition, or a <code>while</code> loop testing the <strong>invalid (opposite)</strong> condition — either is accepted if the logic is correct.</li>\n<li>Re-ask for input <strong>inside</strong> the loop, using the same variable, so the new value actually gets checked.</li>\n</ul>\n<div class=\"code-block\">do\n  mark = input(\"Enter a mark (0-100): \")\nuntil mark &gt;= 0 AND mark &lt;= 100</div>\n<p>A common slip is writing the loop but forgetting to re-read the input inside it — this leaves the program stuck repeating forever on the same invalid value.</p>", "question": "What is a common mistake when writing a validation loop?", "options": ["Using a do…until loop instead of a for loop, since a do…until loop is never an acceptable choice here", "Forgetting to re-read the input inside the loop, so an invalid value never actually gets replaced", "Using AND instead of OR anywhere in the loop''s condition, since AND can never be used in a validation loop", "Asking the user for input before the loop begins, since input must only ever be requested inside a loop"]}'::jsonb, '{"answer": 1, "explain": "If the loop doesn''t re-read input inside its body, the same invalid value is tested forever and the loop never ends."}'::jsonb),
('computer-science:2-3-1-defensive-design:tips:8e48bcf4', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'tips', 'mcq', 1, '{"readingTitle": "tip — Justifying maintainability improvements", "reading": "<p>\"Suggest ways to improve maintainability\" questions want more than a bare list — pair each technique with a brief <strong>reason</strong>.</p>\n<ul>\n<li>Sub-programs → because each part can be tested and reused on its own.</li>\n<li>Meaningful names → because another programmer can tell what a variable is for without tracing the whole program.</li>\n<li>Consistent indentation → because it shows the structure (which lines belong to which loop/selection) at a glance.</li>\n<li>Comments → because they explain what a section does or why, saving time for whoever reads the code next.</li>\n</ul>\n<p>Marks are usually split: <strong>1 for naming</strong> the technique, <strong>1 for the reason</strong> — so always add the \"because…\".</p>", "question": "A question asks you to ''suggest and justify'' a way to improve a program''s maintainability. What must a full-mark answer include?", "options": ["Only the name of a maintainability technique, since a mark scheme never awards marks for giving a reason", "The technique named, plus a reason explaining why it makes the code easier to read, test or change", "A full rewrite of the entire program using every possible maintainability technique available at once", "A description of what the program''s output looks like once the maintainability technique has been applied"]}'::jsonb, '{"answer": 1, "explain": "''Suggest and justify'' questions need the technique AND a reason linking it to easier reading, testing or changing — naming it alone is not enough."}'::jsonb),
