('computer-science:2-3-1-defensive-design:match:572b47c3', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Defensive design”?", "options": ["Designing a program so it copes with unexpected, wrong or malicious input instead of crashing", "Confirms the number of characters entered is within an allowed range", "An automatic check that data is sensible and follows set rules, before it is used", "Confirms data matches a required pattern, such as a postcode"]}'::jsonb, '{"answer": 0, "explain": "“Defensive design” means: Designing a program so it copes with unexpected, wrong or malicious input instead of crashing"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:e0fa405d', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Anticipating misuse”?", "options": ["Confirms a user''s identity before granting them access to a system", "Confirms data is of the correct data type, e.g. a whole number", "Thinking in advance about how a user might enter unsuitable data, and coping with it", "Confirms data was entered or copied correctly, e.g. by entering it twice"]}'::jsonb, '{"answer": 2, "explain": "“Anticipating misuse” means: Thinking in advance about how a user might enter unsuitable data, and coping with it"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:30203d1d', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Input validation”?", "options": ["Confirms a user''s identity before granting them access to a system", "Thinking in advance about how a user might enter unsuitable data, and coping with it", "An automatic check that data is sensible and follows set rules, before it is used", "Designing a program so it copes with unexpected, wrong or malicious input instead of crashing"]}'::jsonb, '{"answer": 2, "explain": "“Input validation” means: An automatic check that data is sensible and follows set rules, before it is used"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:ef078f4d', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Range check”?", "options": ["Confirms the number of characters entered is within an allowed range", "A named, reusable block of code that carries out one clear task", "Confirms that something has actually been entered into a field", "Confirms a value lies between a stated minimum and maximum"]}'::jsonb, '{"answer": 3, "explain": "“Range check” means: Confirms a value lies between a stated minimum and maximum"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:edb8b191', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Type check”?", "options": ["Confirms data was entered or copied correctly, e.g. by entering it twice", "Thinking in advance about how a user might enter unsuitable data, and coping with it", "Confirms data is of the correct data type, e.g. a whole number", "Designing a program so it copes with unexpected, wrong or malicious input instead of crashing"]}'::jsonb, '{"answer": 2, "explain": "“Type check” means: Confirms data is of the correct data type, e.g. a whole number"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:7aca5fe7', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Presence check”?", "options": ["Confirms data is of the correct data type, e.g. a whole number", "Confirms data matches a required pattern, such as a postcode", "Designing a program so it copes with unexpected, wrong or malicious input instead of crashing", "Confirms that something has actually been entered into a field"]}'::jsonb, '{"answer": 3, "explain": "“Presence check” means: Confirms that something has actually been entered into a field"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:f1a124f3', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Length check”?", "options": ["Confirms a user''s identity before granting them access to a system", "Confirms the number of characters entered is within an allowed range", "Confirms data matches a required pattern, such as a postcode", "Confirms that something has actually been entered into a field"]}'::jsonb, '{"answer": 1, "explain": "“Length check” means: Confirms the number of characters entered is within an allowed range"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:fc0c48d5', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Format check”?", "options": ["Confirms data matches a required pattern, such as a postcode", "An automatic check that data is sensible and follows set rules, before it is used", "A named, reusable block of code that carries out one clear task", "Writing code that other programmers can easily read, understand and change"]}'::jsonb, '{"answer": 0, "explain": "“Format check” means: Confirms data matches a required pattern, such as a postcode"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:cf3f9279', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Verification”?", "options": ["Designing a program so it copes with unexpected, wrong or malicious input instead of crashing", "Confirms data is of the correct data type, e.g. a whole number", "Confirms data matches a required pattern, such as a postcode", "Confirms data was entered or copied correctly, e.g. by entering it twice"]}'::jsonb, '{"answer": 3, "explain": "“Verification” means: Confirms data was entered or copied correctly, e.g. by entering it twice"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:c0a65794', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Authentication”?", "options": ["An automatic check that data is sensible and follows set rules, before it is used", "Confirms data was entered or copied correctly, e.g. by entering it twice", "Confirms a user''s identity before granting them access to a system", "Confirms that something has actually been entered into a field"]}'::jsonb, '{"answer": 2, "explain": "“Authentication” means: Confirms a user''s identity before granting them access to a system"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:90e41bd6', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Sub-program”?", "options": ["An automatic check that data is sensible and follows set rules, before it is used", "A named, reusable block of code that carries out one clear task", "Confirms data is of the correct data type, e.g. a whole number", "Confirms data matches a required pattern, such as a postcode"]}'::jsonb, '{"answer": 1, "explain": "“Sub-program” means: A named, reusable block of code that carries out one clear task"}'::jsonb),
('computer-science:2-3-1-defensive-design:match:7146c9eb', 'computer-science', 'computer-science:2-3-1-defensive-design', '2.3.1 Defensive Design', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Maintainability”?", "options": ["Designing a program so it copes with unexpected, wrong or malicious input instead of crashing", "Confirms a value lies between a stated minimum and maximum", "Writing code that other programmers can easily read, understand and change", "Confirms data matches a required pattern, such as a postcode"]}'::jsonb, '{"answer": 2, "explain": "“Maintainability” means: Writing code that other programmers can easily read, understand and change"}'::jsonb),
('computer-science:2-3-2-testing:exam:040c2443', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify the purpose of testing a program.</p>", "options": ["To make the finished program run faster on any computer it is installed on", "To find and remove errors, and check the program meets its requirements", "To translate the program''s source code into machine code so it can run", "To add new features to a program that were not part of its original design"], "hint": "Think about errors AND about requirements."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>To find and remove errors, and check the program meets its requirements</strong></li></ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Only the correct option scores; 2 or more ticks scores 0.</li></ul>\n</div>", "modelAnswer": "To find and remove errors, and check the program meets its requirements."}'::jsonb),
('computer-science:2-3-2-testing:exam:17afb3e9', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'exam', 'mcq', 1, '{"num": "Q2", "question": "<p>Tick <strong>one</strong> box to identify which type of error stops a program being translated or run at all.</p>", "options": ["Logic error", "Syntax error", "Boundary error", "A runtime error caused by invalid data being entered while the program is already running"], "hint": "Which error breaks the rules of the language itself?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Syntax error</strong></li></ul>\n</div>", "modelAnswer": "Syntax error."}'::jsonb),
('computer-science:2-3-2-testing:mcq:db514910', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "What is one purpose of testing a program?", "options": ["To make the finished program run faster on whichever computer it happens to be installed on", "To check the program meets its requirements and works correctly for all kinds of input", "To translate the program''s source code into machine code so that it is able to run", "To document every line of code so that another programmer could read it later on"]}'::jsonb, '{"answer": 1, "explain": "Testing checks a program meets its requirements and works for all kinds of input. Translating code and documenting it are different tasks."}'::jsonb),
('computer-science:2-3-2-testing:mcq:979bcec4', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "Which best describes iterative testing?", "options": ["Testing the complete, finished program once, right at the very end of development", "Testing modules or parts of the program repeatedly as it is developed and refined", "Asking real users to test the finished program after it has already been released", "Running the finished program on several different makes and models of computer"]}'::jsonb, '{"answer": 1, "explain": "Iterative testing repeats throughout development, testing parts of the program as they are built and refined. Testing once at the end is final (terminal) testing."}'::jsonb),
('computer-science:2-3-2-testing:mcq:6e0f568e', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "Which best describes final (terminal) testing?", "options": ["Testing each small module the moment it is first written, before any other code exists", "Testing the complete program, once it is finished, against its original requirements", "Testing carried out by the end user rather than by the programmer who wrote the code", "Testing that only ever checks for syntax errors and nothing else about the program"]}'::jsonb, '{"answer": 1, "explain": "Final (terminal) testing happens once, at the end, testing the whole finished program against its requirements — not one module at a time during development."}'::jsonb),
('computer-science:2-3-2-testing:mcq:ce684dce', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "A program has a missing closing bracket, so it cannot be run at all. What type of error is this?", "options": ["A logic error, because the missing bracket produces the wrong result once the program runs", "A syntax error", "A boundary error caused by a value being placed right at the edge of what is accepted", "A test-plan error, because it is really a mistake in how the program was tested, not written"]}'::jsonb, '{"answer": 1, "explain": "Breaking the rules of the language (like a missing bracket) so the program can''t run at all is a syntax error. A logic error still lets the program run."}'::jsonb),
('computer-science:2-3-2-testing:mcq:fe2a95fa', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "A program runs without crashing, but always calculates the wrong total. What type of error is this?", "options": ["A syntax error, since the program is clearly breaking one of the rules of the language it is written in", "A logic error", "An erroneous-data error, since this can only ever be caused by the user entering the wrong data", "There is no error here at all, since the program does successfully run all the way through"]}'::jsonb, '{"answer": 1, "explain": "The program runs (so the language rules are followed correctly) but gives the wrong result — that is a logic error, not a syntax error."}'::jsonb),
('computer-science:2-3-2-testing:mcq:33d188d9', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "How are syntax errors usually found?", "options": ["Automatically, by the translator, which reports an error message when the program is run", "By testing the program with data where the correct answer is already known in advance", "By asking a different programmer to read through every single line of the code by eye", "They cannot be found until after the finished program has already been released to users"]}'::jsonb, '{"answer": 0, "explain": "The translator automatically detects syntax errors and reports them, because the code breaks the language''s own rules. Logic errors need testing instead."}'::jsonb),
('computer-science:2-3-2-testing:mcq:cdd6bd84', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "A program accepts a whole number from 1 to 50. Which of these is NORMAL test data?", "options": ["25", "50, since it is the very largest whole number that the program is designed to accept", "51, since it is a whole number that is just one more than the program should ever allow", "''fifty'', since typing the word instead of the digits is not the right type of data at all"]}'::jsonb, '{"answer": 0, "explain": "25 is a typical, valid value comfortably inside the range — normal data. 50 is boundary, 51 is invalid, and ''fifty'' is erroneous."}'::jsonb),
('computer-science:2-3-2-testing:mcq:f3dd2dbd', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "Using the same program (accepts 1 to 50), which of these is BOUNDARY test data?", "options": ["25, since it sits roughly in the middle of the range and is the most ordinary value to try", "50", "51, since it is the very first whole number that falls just outside the accepted range", "''fifty'', since typing the word instead of the digits is the most extreme input imaginable"]}'::jsonb, '{"answer": 1, "explain": "50 is the maximum valid value — a boundary value. 25 is normal, 51 is invalid (correct type, out of range), and ''fifty'' is erroneous (wrong type)."}'::jsonb),
('computer-science:2-3-2-testing:mcq:53076f60', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "Using the same program (accepts 1 to 50), which of these is INVALID test data?", "options": ["25, since it sits comfortably inside the accepted range and is a perfectly typical value", "50, since it is the largest whole number that the program should still accept as valid", "51", "''fifty'', since it is text rather than a number and is therefore not the correct type at all"]}'::jsonb, '{"answer": 2, "explain": "51 is a whole number (the correct type) but outside the 1–50 range — invalid. ''fifty'' is the wrong type entirely, which makes it erroneous, not invalid."}'::jsonb),
('computer-science:2-3-2-testing:mcq:5a5b751b', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "Using the same program (accepts 1 to 50), which of these is ERRONEOUS test data?", "options": ["25, since it sits comfortably inside the range and is a completely ordinary value to try", "50, since it is the largest whole number that the program is designed to accept", "51, since it is a whole number that is just one more than the highest accepted value", "''fifty''"]}'::jsonb, '{"answer": 3, "explain": "''fifty'' is text, not a number — the wrong type of data entirely, which makes it erroneous. 51 is the correct type but out of range, so it is invalid instead."}'::jsonb),
('computer-science:2-3-2-testing:mcq:a0f4ab97', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "What should a test plan record about a test, before it is actually carried out?", "options": ["The expected result", "The actual result, since this is the only column that genuinely matters in a test plan", "The name of the programmer who will eventually be blamed if the test happens to fail", "The exact time and date on which the finished program will finally be released"]}'::jsonb, '{"answer": 0, "explain": "The expected result should be written before running the test, so it can be compared fairly against the actual result to judge pass or fail."}'::jsonb),
('computer-science:2-3-2-testing:mcq:a0b285e2', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'mcq', 'mcq', 1, '{"question": "A test plan row shows: test data 0, type boundary, expected result ''accepted'', actual result ''rejected''. What does this tell the programmer?", "options": ["The test has passed, because 0 was a boundary value and boundary values should always automatically be rejected outright", "The test has failed — the program wrongly rejected a value it should have accepted, so the code needs correcting", "Nothing useful, since boundary values are not really considered a meaningful type of test data to use at all", "The test data itself was chosen rather badly and should have been normal data instead of boundary data"]}'::jsonb, '{"answer": 1, "explain": "The expected and actual results don''t match (expected accepted, actually rejected), so the test fails — the validation code needs fixing, then re-testing."}'::jsonb),
('computer-science:2-3-2-testing:tf:ec1d049d', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tf', 'tf', 1, '{"question": "The purpose of testing is only to find errors, not to check the program meets its requirements."}'::jsonb, '{"answer": false, "explain": "Testing also checks the program meets its requirements and works for all kinds of input — not just error-finding."}'::jsonb)
